#include <stdio.h>
#include <stdlib.h>

#define N 1000

int main() {
    int T, n, i, a[N], sum = 0;
    double p = 0.5, res = 0;

    scanf("%d", &T);

    while (T--) {
        scanf("%d", &n);

        for (i = 0; i < n; i++) {
            scanf("%d", &a[i]);
            sum += a[i];
        }

        res = 0;

        for (i = 0; i < n; i++) {
            res += (p * a[i] + (1 - p) * a[n - i - 1]) / 2;
            p = 1 - p;
        }

        printf("%.6f\n", res);

        sum = 0;
        p = 0.5;
    }

    return 0;
}

