#include <iostream>
#include <vector>
#include <cmath>

using namespace std;

int main() {
    int T, n, i;
    double p = 0.5, res = 0;

    cin >> T;

    while (T--) {
        cin >> n;

        vector<int> a(n);

        for (i = 0; i < n; i++) {
            cin >> a[i];
        }

        res = 0;

        for (i = 0; i < n; i++) {
            res += (p * a[i] + (1 - p) * a[n - i - 1]) / 2;
            p = 1 - p;
        }

        cout << fixed << setprecision(6) << res << endl;
    }

    return 0;
}

code.Java:
public class Main {
    public static void main(String[] args) {
        int T, n, i;
        double p = 0.5, res = 0;

        java.util.Scanner sc = new java.util.Scanner(System.in);

        sc.nextInt();

        while (sc.hasNextInt()) {
            T = sc.nextInt();

            while (T-- > 0) {
                n = sc.nextInt();

                int[] a = new int[n];

                for (i = 0; i < n; i++) {
                    a[i] = sc.nextInt();
                }

                res = 0;

                for (i = 0; i < n; i++) {
                    res += (p * a[i] + (1 - p) * a[n - i - 1]) / 2;
                    p = 1 - p;
                }

                System.out.printf("%.6f\n", res);
            }
        }
    }
}

